@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Figtree", sans-serif;
  background: transparent;
  color: #05042E;
  font-size: 13px;
}

.wrap {
  padding: 16px;
}

.drive-card {
  border-radius: 10px;
  padding: 14px 16px;
  margin-bottom: 12px;
  border: 0.5px solid rgba(0, 0, 0, 0.12);
}

.drive-card.erased {
  background: rgba(163, 232, 81, 0.08);
  border-color: rgba(163, 232, 81, 0.4);
}

.drive-card.failed {
  background: #fee2e2;
  border-color: #fca5a5;
}

.drive-card.manual {
  background: rgba(70, 155, 192, 0.06);
  border-color: rgba(70, 155, 192, 0.2);
}

.drive-card.shredded {
  background: rgba(5, 4, 46, 0.04);
  border-color: rgba(0, 0, 0, 0.1);
}

.card-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 10px;
}

.card-title {
  font-size: 13px;
  font-weight: 700;
  color: #05042E;
  display: flex;
  align-items: center;
  gap: 8px;
}

.status-pill {
  font-size: 10px;
  font-weight: 700;
  padding: 3px 10px;
  border-radius: 20px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.pill-erased {
  background: rgba(163, 232, 81, 0.2);
  color: #5a8a1a;
  border: 1px solid rgba(163, 232, 81, 0.4);
}

.pill-failed {
  background: #fee2e2;
  color: #b91c1c;
  border: 1px solid #fca5a5;
}

.pill-pending {
  background: rgba(5, 4, 46, 0.06);
  color: #888780;
  border: 1px solid rgba(0, 0, 0, 0.1);
}

.pill-shredded {
  background: rgba(5, 4, 46, 0.06);
  color: #888780;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
}

.drive-fields {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
  margin-bottom: 12px;
}

.drive-field {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.field-label {
  font-size: 10px;
  font-weight: 600;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.field-value {
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
}

.field-input {
  font-size: 13px;
  font-family: "Figtree", sans-serif;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  padding: 6px 10px;
  color: #05042E;
  outline: none;
  width: 100%;
  background: #fff;
}

.field-input:focus {
  border-color: #469BC0;
}

.card-actions {
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
}

.btn {
  font-size: 12px;
  font-weight: 700;
  padding: 7px 16px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
  font-family: "Figtree", sans-serif;
  transition: all 0.15s;
}

.btn-shred {
  background: #05042E;
  color: #A3E851;
}

.btn-shred:hover {
  background: #469BC0;
  color: #fff;
}

.btn-shred-record {
  background: rgba(163, 232, 81, 0.15);
  color: #5a8a1a;
  border: 1px solid rgba(163, 232, 81, 0.4);
}

.btn-shred-record:hover {
  background: rgba(163, 232, 81, 0.3);
}

.btn-secondary {
  background: #f1f5f9;
  color: #05042E;
  border: 1px solid #e2e8f0;
}

.btn-secondary:hover {
  background: #e2e8f0;
}

.btn-danger {
  background: #fee2e2;
  color: #b91c1c;
  border: 1px solid #fca5a5;
}

.btn-danger:hover {
  background: #fca5a5;
}

.btn-green {
  background: #A3E851;
  color: #05042E;
}

.btn-green:hover {
  background: #8bc93d;
}

.section-title {
  font-size: 11px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin-bottom: 8px;
}

.shred-records {
  margin-top: 16px;
}

.shred-record-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 12px;
  border-radius: 8px;
  background: rgba(5, 4, 46, 0.02);
  border: 0.5px solid rgba(0, 0, 0, 0.08);
  margin-bottom: 6px;
}

.shred-icon {
  font-size: 16px;
  flex-shrink: 0;
}

.shred-info {
  flex: 1;
}

.shred-ref {
  font-size: 12px;
  font-weight: 700;
  color: #05042E;
}

.shred-meta {
  font-size: 11px;
  color: #888780;
  margin-top: 1px;
}

.shred-pallet {
  font-size: 11px;
  color: #469BC0;
  font-weight: 600;
}

.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.4);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
}

.modal {
  background: #fff;
  border-radius: 12px;
  padding: 20px;
  width: 90%;
  max-width: 420px;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.2);
}

.modal-title {
  font-size: 15px;
  font-weight: 700;
  color: #05042E;
  margin-bottom: 16px;
}

.modal-field {
  margin-bottom: 12px;
}

.modal-label {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 4px;
}

.modal-input {
  font-size: 13px;
  font-family: "Figtree", sans-serif;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  padding: 8px 10px;
  color: #05042E;
  outline: none;
  width: 100%;
  background: #fff;
}

.modal-input:focus {
  border-color: #469BC0;
}

.modal-select {
  font-size: 13px;
  font-family: "Figtree", sans-serif;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  padding: 8px 10px;
  color: #05042E;
  outline: none;
  width: 100%;
  background: #fff;
}

.modal-actions {
  display: flex;
  gap: 8px;
  justify-content: flex-end;
  margin-top: 16px;
}

.divider {
  border: none;
  border-top: 0.5px solid rgba(0, 0, 0, 0.08);
  margin: 14px 0;
}

.empty-state {
  text-align: center;
  padding: 24px;
  color: #888780;
  font-size: 13px;
}

.new-pallet-link {
  font-size: 12px;
  color: #469BC0;
  cursor: pointer;
  text-decoration: underline;
  margin-top: 6px;
  display: inline-block;
}

.warning-text {
  font-size: 11px;
  color: #b91c1c;
  margin-top: 6px;
}

