import React, { useState, useEffect } from 'https://esm.sh/react@18.2.0';
import { createRoot } from 'https://esm.sh/react-dom@18.2.0/client';

const NAVY = '#05042E';
const BLUE = '#469BC0';
const GREEN = '#A3E851';

function fmtDate(d) {
	if (!d) return '—';
	return new Date(d).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit' });
}

function fmtUser(email) {
	if (!email) return '—';
	return email.split('@')[0];
}

function ShredModal({ drive, shredType, openPallets, onClose, onConfirm }) {
	const [selectedPallet, setSelectedPallet] = useState('');
	const [createNew, setCreateNew] = useState(openPallets.length === 0);
	const [notes, setNotes] = useState('');
	const [manualSerial, setManualSerial] = useState(drive.serial || '');
	const [manualModel, setManualModel] = useState(drive.model || '');
	const [manualInterface, setManualInterface] = useState(drive.interface_type || '');
	const [manualCapacity, setManualCapacity] = useState(drive.capacity || '');

	const isManual = shredType === 'manual';

	return React.createElement('div', { className: 'modal-overlay', onClick: onClose },
		React.createElement('div', { className: 'modal', onClick: e => e.stopPropagation() },
			React.createElement('div', { className: 'modal-title' },
				isManual ? '📋 Log Drive for Shred' : '🔥 Create Shred Record'
			),

			isManual && React.createElement('div', null,
				React.createElement('div', { className: 'modal-field' },
					React.createElement('div', { className: 'modal-label' }, 'Drive Serial'),
					React.createElement('input', { className: 'modal-input', value: manualSerial, onChange: e => setManualSerial(e.target.value), placeholder: 'Enter drive serial number' })
				),
				React.createElement('div', { className: 'modal-field' },
					React.createElement('div', { className: 'modal-label' }, 'Drive Model'),
					React.createElement('input', { className: 'modal-input', value: manualModel, onChange: e => setManualModel(e.target.value), placeholder: 'e.g. WD Blue 500GB' })
				),
				React.createElement('div', { className: 'modal-field' },
					React.createElement('div', { className: 'modal-label' }, 'Interface'),
					React.createElement('input', { className: 'modal-input', value: manualInterface, onChange: e => setManualInterface(e.target.value), placeholder: 'e.g. SATA, NVMe' })
				),
				React.createElement('div', { className: 'modal-field' },
					React.createElement('div', { className: 'modal-label' }, 'Capacity'),
					React.createElement('input', { className: 'modal-input', value: manualCapacity, onChange: e => setManualCapacity(e.target.value), placeholder: 'e.g. 500GB' })
				)
			),

			React.createElement('div', { className: 'modal-field' },
				React.createElement('div', { className: 'modal-label' }, 'HDD Waste Pallet'),
				!createNew && openPallets.length > 0
					? React.createElement('div', null,
						React.createElement('select', {
							className: 'modal-select', value: selectedPallet,
							onChange: e => setSelectedPallet(e.target.value)
						},
							React.createElement('option', { value: '' }, '-- Select pallet --'),
							openPallets.map(p => React.createElement('option', { key: p.pallet_id, value: p.pallet_id }, p.waste_id + ' (' + (p.waste_type || 'HDD') + ')'))
						),
						React.createElement('span', { className: 'new-pallet-link', onClick: () => setCreateNew(true) }, '+ Create new HDD pallet instead')
					)
					: React.createElement('div', null,
						React.createElement('div', { style: { fontSize: '12px', color: '#469BC0', background: 'rgba(70,155,192,0.08)', padding: '8px 12px', borderRadius: '6px', border: '0.5px solid rgba(70,155,192,0.2)' } },
							'✓ A new HDD Shred pallet will be created automatically'
						),
						openPallets.length > 0 && React.createElement('span', { className: 'new-pallet-link', onClick: () => setCreateNew(false) }, '← Use existing pallet instead')
					)
			),

			React.createElement('div', { className: 'modal-field' },
				React.createElement('div', { className: 'modal-label' }, 'Notes (optional)'),
				React.createElement('textarea', {
					className: 'modal-input', value: notes,
					onChange: e => setNotes(e.target.value),
					rows: 2, placeholder: 'Any additional notes about this shred...',
					style: { resize: 'vertical' }
				})
			),

			React.createElement('div', { className: 'modal-actions' },
				React.createElement('button', { className: 'btn btn-secondary', onClick: onClose }, 'Cancel'),
				React.createElement('button', {
					className: 'btn btn-shred',
					onClick: () => onConfirm({
						pallet_id: createNew ? null : selectedPallet,
						create_new_pallet: createNew,
						notes: notes,
						serial: manualSerial,
						model: manualModel,
						interface: manualInterface,
						capacity: manualCapacity,
						shred_type: shredType
					})
				}, shredType === 'manual' ? 'Log for Shred' : 'Confirm Shred Record')
			)
		)
	);
}

function DriveCard({ drive, shredRecords, openPallets, onShred }) {
	const [showModal, setShowModal] = useState(false);
	const [shredType, setShredType] = useState('blancco_failed');

	const erasure = (drive.erasure_status || '').toLowerCase();
	const hasBlancco = !!drive.erasure_status && drive.erasure_status !== '—';
	const isErased = erasure.includes('success') || erasure === 'erased';
	const isFailed = erasure.includes('fail') || erasure.includes('error');

	// shred records matched to this specific drive's serial
	const driveShredRecords = (shredRecords || []).filter(r => r.drive_serial === drive.serial);
	const isShredded = driveShredRecords.length > 0;

	const cardClass = isShredded ? 'drive-card shredded' : isErased ? 'drive-card erased' : isFailed ? 'drive-card failed' : 'drive-card manual';

	const openShred = (type) => {
		setShredType(type);
		setShowModal(true);
	};

	return React.createElement('div', null,
		React.createElement('div', { className: cardClass },
			React.createElement('div', { className: 'card-header' },
				React.createElement('div', { className: 'card-title' },
					React.createElement('span', null, '💾'),
					React.createElement('span', null, drive.model || 'Drive / Storage'),
					drive.disk_index && React.createElement('span', { style: { fontSize: '11px', fontWeight: 600, color: '#888780' } }, ' #' + drive.disk_index)
				),
				isShredded
					? React.createElement('div', { style: { display: 'flex', gap: '6px' } },
						isFailed && React.createElement('span', { className: 'status-pill pill-failed' }, '✗ Erasure Failed'),
						React.createElement('span', { className: 'status-pill pill-shredded' }, '🔥 Shredded')
					)
					: isErased
					? React.createElement('span', { className: 'status-pill pill-erased' }, '✓ Erased')
					: isFailed
					? React.createElement('span', { className: 'status-pill pill-failed' }, '✗ Erasure Failed')
					: React.createElement('span', { className: 'status-pill pill-pending' }, 'No Erasure Data')
			),

			React.createElement('div', { className: 'drive-fields' },
				React.createElement('div', { className: 'drive-field' },
					React.createElement('div', { className: 'field-label' }, 'Capacity'),
					React.createElement('div', { className: 'field-value' }, drive.capacity || '—')
				),
				React.createElement('div', { className: 'drive-field' },
					React.createElement('div', { className: 'field-label' }, 'Serial'),
					React.createElement('div', { className: 'field-value' }, drive.serial || '—')
				),
				React.createElement('div', { className: 'drive-field' },
					React.createElement('div', { className: 'field-label' }, 'Interface'),
					React.createElement('div', { className: 'field-value' }, drive.interface_type || '—')
				),
				React.createElement('div', { className: 'drive-field' },
					React.createElement('div', { className: 'field-label' }, 'Erasure Standard'),
					React.createElement('div', { className: 'field-value' }, drive.erasure_standard || '—')
				)
			),

			(drive.erasure_start_time || drive.erasure_end_time || isShredded) && React.createElement('div', { style: { display: 'flex', flexDirection: 'column', gap: '2px', marginBottom: '10px', fontSize: '11px', color: '#888780' } },
				drive.erasure_start_time && React.createElement('span', null, 'Blancco erasure started: ' + fmtDate(drive.erasure_start_time)),
				drive.erasure_end_time && React.createElement('span', null, 'Blancco erasure completed: ' + fmtDate(drive.erasure_end_time)),
				isShredded && React.createElement('span', null, 'Shredded: ' + fmtDate(driveShredRecords[0]?.shred_date) + (driveShredRecords[0]?.shred_by ? ' by ' + fmtUser(driveShredRecords[0].shred_by) : ''))
			),

			React.createElement('div', { className: 'card-actions' },
				!isShredded && isFailed && React.createElement('button', { className: 'btn btn-danger', onClick: () => openShred('blancco_failed') }, '🔥 Shred — Erasure Failed'),
				!isShredded && isErased && React.createElement('button', { className: 'btn btn-shred-record', onClick: () => openShred('blancco_success') }, '📋 Create Shred Record'),
				!isShredded && !hasBlancco && React.createElement('button', { className: 'btn btn-shred', onClick: () => openShred('manual') }, '📋 Log Drive for Shred')
			)
		),

		showModal && React.createElement(ShredModal, {
			drive: drive,
			openPallets: openPallets,
			shredType: shredType,
			onClose: () => setShowModal(false),
			onConfirm: (data) => {
				setShowModal(false);
				onShred(data, drive);
			}
		})
	);
}

function ManualDriveCard({ openPallets, onShred }) {
	const [showModal, setShowModal] = useState(false);

	return React.createElement('div', null,
		React.createElement('div', { className: 'drive-card manual' },
			React.createElement('div', { className: 'card-header' },
				React.createElement('div', { className: 'card-title' }, '💾  Manual Drive Entry'),
				React.createElement('span', { className: 'status-pill pill-pending' }, 'No Drive Data')
			),
			React.createElement('p', { style: { fontSize: '12px', color: '#888780', marginBottom: '10px' } }, 'No drive data from Blancco. Use this to manually log a drive for shredding.'),
			React.createElement('button', { className: 'btn btn-shred', onClick: () => setShowModal(true) }, '📋 Log Drive for Shred')
		),

		showModal && React.createElement(ShredModal, {
			drive: { serial: '', model: '', interface_type: '', capacity: '' },
			openPallets: openPallets,
			shredType: 'manual',
			onClose: () => setShowModal(false),
			onConfirm: (data) => {
				setShowModal(false);
				onShred(data, null);
			}
		})
	);
}

function ShredHistory({ records }) {
	if (!records || records.length === 0) return null;
	return React.createElement('div', { className: 'shred-records' },
		React.createElement('div', { className: 'section-title' }, 'Shred Records'),
		records.map(r => React.createElement('div', { key: r.shred_id, className: 'shred-record-item' },
			React.createElement('div', { className: 'shred-icon' }, '🔥'),
			React.createElement('div', { className: 'shred-info' },
				React.createElement('div', { className: 'shred-ref' }, (r.drive_model || r.drive_serial || 'Drive') + ' — ' + (r.shred_type === 'manual' ? 'Manual Log' : r.shred_type === 'blancco_failed' ? 'Shred (Erasure Failed)' : 'Shred Record')),
				React.createElement('div', { className: 'shred-meta' }, fmtDate(r.shred_date) + ' · ' + fmtUser(r.shred_by)),
				r.pallet_ref && React.createElement('div', { className: 'shred-pallet' }, '📦 ' + r.pallet_ref)
			)
		))
	);
}

function App({ model }) {
	const asset = model.asset || {};
	const drives = model.drives || [];
	const shredRecords = model.shredRecords || [];
	const openPallets = model.openPallets || [];

	const handleShred = (data, drive) => {
		const payload = {
			shred_serial: data.serial || (drive && drive.serial) || '',
			shred_model: data.model || (drive && drive.model) || '',
			shred_interface: data.interface || (drive && drive.interface_type) || '',
			shred_capacity: data.capacity || (drive && drive.capacity) || '',
			shred_type: data.shred_type || 'manual',
			shred_pallet_id: data.pallet_id || null,
			shred_create_new_pallet: data.create_new_pallet || false,
			shred_notes: data.notes || ''
		};
		appsmith.updateModel(payload);
		appsmith.triggerEvent('onShred');
	};

	return React.createElement('div', { className: 'wrap' },
		drives.length > 0
			? drives.map(drive => React.createElement(DriveCard, {
				key: drive.id || drive.serial || drive.disk_index,
				drive,
				shredRecords,
				openPallets,
				onShred: handleShred
			}))
			: React.createElement(ManualDriveCard, { openPallets, onShred: handleShred }),
		React.createElement(ShredHistory, { records: shredRecords })
	);
}

var _root = null;
function renderApp() {
	var c = document.getElementById('root');
	if (!_root) { _root = createRoot(c); }
	var m = appsmith.model || {};
	_root.render(React.createElement(App, { model: m }));
}
appsmith.onReady(function() { renderApp(); });
appsmith.onModelChange(function() { renderApp(); });
